def clean(self):
    super().clean()
    self.email = self.__class__.objects.normalize_email(self.email)

def executemany(self, query, param_list):
    query = self.convert_query(query)
    return Database.Cursor.executemany(self, query, param_list)

def _execute(self, sql, params, *ignored_wrapper_args):
    self.db.validate_no_broken_transaction()
    with self.db.wrap_database_errors:
        if params is None:
            # params default might be backend specific.
            return self.cursor.execute(sql)
        else:
            return self.cursor.execute(sql, params)

def get_combinator_sql(self, combinator, all):
    features = self.connection.features
    compilers = [
        query.get_compiler(self.using, self.connection)
        for query in self.query.combined_queries if not query.is_empty()
    ]
    if not features.supports_slicing_ordering_in_compound:
        for query, compiler in zip(self.query.combined_queries, compilers):
            if query.low_mark or query.high_mark:
                raise DatabaseError('LIMIT/OFFSET not allowed in subqueries of compound statements.')
            if compiler.get_order_by():
                raise DatabaseError('ORDER BY not allowed in subqueries of compound statements.')
    parts = ()
    for compiler in compilers:
        try:
            # If the columns list is limited, then all combined queries
            # must have the same columns list. Set the selects defined on
            # the query on all combined queries, if not already set.
            if not compiler.query.values_select and self.query.values_select:
                compiler.query = compiler.query.clone()
                compiler.query.set_values((
                    *self.query.extra_select,
                    *self.query.values_select,
                    *self.query.annotation_select,
                ))
            part_sql, part_args = compiler.as_sql()
            if compiler.query.combinator:
                # Wrap in a subquery if wrapping in parentheses isn't
                # supported.
                if not features.supports_parentheses_in_compound:
                    part_sql = 'SELECT * FROM ({})'.format(part_sql)
                # Add parentheses when combining with compound query if not
                # already added for all compound queries.
                elif not features.supports_slicing_ordering_in_compound:
                    part_sql = '({})'.format(part_sql)
            parts += ((part_sql, part_args),)
        except EmptyResultSet:
            # Omit the empty queryset with UNION and with DIFFERENCE if the
            # first queryset is nonempty.
            if combinator == 'union' or (combinator == 'difference' and parts):
                continue
            raise
    if not parts:
        raise EmptyResultSet
    combinator_sql = self.connection.ops.set_operators[combinator]
    if all and combinator == 'union':
        combinator_sql += ' ALL'
    braces = '({})' if features.supports_slicing_ordering_in_compound else '{}'
    sql_parts, args_parts = zip(*((braces.format(sql), args) for sql, args in parts))
    result = [' {} '.format(combinator_sql).join(sql_parts)]
    params = []
    for part in args_parts:
        params.extend(part)
    return result, params

def __set__(self, instance, value):
    if instance.__dict__.get(self.field.attname) != value and self.field.is_cached(instance):
        self.field.delete_cached_value(instance)
    instance.__dict__[self.field.attname] = value

def get_db_prep_save(self, value, connection):
    if value is None or (value == '' and
                         (not self.target_field.empty_strings_allowed or
                          connection.features.interprets_empty_strings_as_nulls)):
        return None
    else:
        return self.target_field.get_db_prep_save(value, connection=connection)

def options(self, name, value, attrs=None):
    """Yield a flat list of options for this widgets."""
    for group in self.optgroups(name, value, attrs):
        yield from group[1]

def id_for_label(self, id_):
    if id_:
        id_ += '_0'
    return id_

def id_for_label(self, id_):
    for first_select in self._parse_date_fmt():
        return '%s_%s' % (id_, first_select)
    return '%s_month' % id_

def id_for_label(self, id_, index=None):
    """
    Don't include for="field_0" in <label> to improve accessibility when
    using a screen reader, in addition clicking such a label would toggle
    the first input.
    """
    if index is None:
        return ''
    return super().id_for_label(id_, index)

def rename_index(self, model, old_index, new_index):
    if self.connection.features.can_rename_index:
        self.execute(
            self._rename_index_sql(model, old_index.name, new_index.name),
            params=None,
        )
    else:
        self.remove_index(model, old_index)
        self.add_index(model, new_index)

def add_index(self, model, index):
    """Add an index on a model."""
    if (
        index.contains_expressions
        and not self.connection.features.supports_expression_indexes
    ):
        return None
    # Index.create_sql returns interpolated SQL which makes params=None a
    # necessity to avoid escaping attempts on execution.
    self.execute(index.create_sql(model, self), params=None)

def remove_index(self, model, index):
    """Remove an index from a model."""
    if (
        index.contains_expressions
        and not self.connection.features.supports_expression_indexes
    ):
        return None
    self.execute(index.remove_sql(model, self))

def add_index(self, model, index, concurrently=False):
    self.execute(
        index.create_sql(model, self, concurrently=concurrently), params=None
    )

def format_callback(obj):
    model = obj.__class__
    has_admin = model in admin_site._registry
    opts = obj._meta

    no_edit_link = "%s: %s" % (capfirst(opts.verbose_name), obj)

    if has_admin:
        if not admin_site._registry[model].has_delete_permission(request, obj):
            perms_needed.add(opts.verbose_name)
        try:
            admin_url = reverse(
                "%s:%s_%s_change"
                % (admin_site.name, opts.app_label, opts.model_name),
                None,
                (quote(obj.pk),),
            )
        except NoReverseMatch:
            # Change url doesn't exist -- don't display link to edit
            return no_edit_link

        # Display a link to the admin page.
        return format_html(
            '{}: <a href="{}">{}</a>', capfirst(opts.verbose_name), admin_url, obj
        )
    else:
        # Don't display link to edit, because it either has no
        # admin or is edited inline.
        return no_edit_link

def get_ordering(self, request, queryset):
    """
    Return the list of ordering fields for the change list.
    First check the get_ordering() method in model admin, then check
    the object's default ordering. Then, any manually-specified ordering
    from the query string overrides anything. Finally, a deterministic
    order is guaranteed by calling _get_deterministic_ordering() with the
    constructed ordering.
    """
    params = self.params
    ordering = list(
        self.model_admin.get_ordering(request) or self._get_default_ordering()
    )
    if ORDER_VAR in params:
        # Clear ordering and used params
        ordering = []
        order_params = params[ORDER_VAR].split(".")
        for p in order_params:
            try:
                none, pfx, idx = p.rpartition("-")
                field_name = self.list_display[int(idx)]
                order_field = self.get_ordering_field(field_name)
                if not order_field:
                    continue  # No 'admin_order_field', skip it
                if isinstance(order_field, OrderBy):
                    if pfx == "-":
                        order_field = order_field.copy()
                        order_field.reverse_ordering()
                    ordering.append(order_field)
                elif hasattr(order_field, "resolve_expression"):
                    # order_field is an expression.
                    ordering.append(
                        order_field.desc() if pfx == "-" else order_field.asc()
                    )
                # reverse order if order_field has already "-" as prefix
                elif order_field.startswith("-") and pfx == "-":
                    ordering.append(order_field[1:])
                else:
                    ordering.append(pfx + order_field)
            except (IndexError, ValueError):
                continue  # Invalid ordering specified, skip it.

    # Add the given query's ordering fields, if any.
    ordering.extend(queryset.query.order_by)

    return self._get_deterministic_ordering(ordering)

def get_query_string(self, new_params=None, remove=None):
    if new_params is None:
        new_params = {}
    if remove is None:
        remove = []
    p = self.params.copy()
    for r in remove:
        for k in list(p):
            if k.startswith(r):
                del p[k]
    for k, v in new_params.items():
        if v is None:
            if k in p:
                del p[k]
        else:
            p[k] = v
    return "?%s" % urlencode(sorted(p.items()))

def _get_default_ordering(self):
    ordering = []
    if self.model_admin.ordering:
        ordering = self.model_admin.ordering
    elif self.lookup_opts.ordering:
        ordering = self.lookup_opts.ordering
    return ordering

def get_ordering_field(self, field_name):
    """
    Return the proper model field name corresponding to the given
    field_name to use for ordering. field_name may either be the name of a
    proper model field or the name of a method (on the admin or model) or a
    callable with the 'admin_order_field' attribute. Return None if no
    proper model field name can be matched.
    """
    try:
        field = self.lookup_opts.get_field(field_name)
        return field.name
    except FieldDoesNotExist:
        # See whether field_name is a name of a non-field
        # that allows sorting.
        if callable(field_name):
            attr = field_name
        elif hasattr(self.model_admin, field_name):
            attr = getattr(self.model_admin, field_name)
        else:
            attr = getattr(self.model, field_name)
        if isinstance(attr, property) and hasattr(attr, "fget"):
            attr = attr.fget
        return getattr(attr, "admin_order_field", None)

def get_ordering_field_columns(self):
    """
    Return a dictionary of ordering field column numbers and asc/desc.
    """
    # We must cope with more than one column having the same underlying sort
    # field, so we base things on column numbers.
    ordering = self._get_default_ordering()
    ordering_fields = {}
    if ORDER_VAR not in self.params:
        # for ordering specified on ModelAdmin or model Meta, we don't know
        # the right column numbers absolutely, because there might be more
        # than one column associated with that ordering, so we guess.
        for field in ordering:
            if isinstance(field, (Combinable, OrderBy)):
                if not isinstance(field, OrderBy):
                    field = field.asc()
                if isinstance(field.expression, F):
                    order_type = "desc" if field.descending else "asc"
                    field = field.expression.name
                else:
                    continue
            elif field.startswith("-"):
                field = field[1:]
                order_type = "desc"
            else:
                order_type = "asc"
            for index, attr in enumerate(self.list_display):
                if self.get_ordering_field(attr) == field:
                    ordering_fields[index] = order_type
                    break
    else:
        for p in self.params[ORDER_VAR].split("."):
            none, pfx, idx = p.rpartition("-")
            try:
                idx = int(idx)
            except ValueError:
                continue  # skip it
            ordering_fields[idx] = "desc" if pfx == "-" else "asc"
    return ordering_fields

def clf():
    """Clear the current figure."""
    gcf().clear()

def draw(self, renderer):
    # docstring inherited

    # draw the figure bounding box, perhaps none for white figure
    if not self.get_visible():
        return

    artists = self._get_draw_artists(renderer)
    try:
        renderer.open_group('figure', gid=self.get_gid())
        if self.axes and self.get_layout_engine() is not None:
            try:
                self.get_layout_engine().execute(self)
            except ValueError:
                pass
                # ValueError can occur when resizing a window.

        self.patch.draw(renderer)
        mimage._draw_list_compositing_images(
            renderer, self, artists, self.suppressComposite)

        for sfig in self.subfigs:
            sfig.draw(renderer)

        renderer.close_group('figure')
    finally:
        self.stale = False

    DrawEvent("draw_event", self.canvas, renderer)._process()

def _parse_toml(self, config_file: Path, parser: configparser.ConfigParser) -> None:
    """Parse and handle errors of a toml configuration file."""
    with open(config_file, mode="rb") as fp:
        content = tomllib.load(fp)
    try:
        sections_values = content["tool"]["pylint"]
    except KeyError:
        return
    for section, values in sections_values.items():
        section_name = section.upper()
        # TOML has rich types, convert values to
        # strings as ConfigParser expects.
        if not isinstance(values, dict):
            # This class is a mixin: add_message comes from the `PyLinter` class
            self.add_message(  # type: ignore[attr-defined]
                "bad-configuration-section", line=0, args=(section, values)
            )
            continue
        for option, value in values.items():
            if isinstance(value, bool):
                values[option] = "yes" if value else "no"
            elif isinstance(value, list):
                values[option] = ",".join(value)
            else:
                values[option] = str(value)
        for option, value in values.items():
            try:
                parser.set(section_name, option, value=value)
            except configparser.NoSectionError:
                parser.add_section(section_name)
                parser.set(section_name, option, value=value)

def load_provider_defaults(self):
    """Initialize configuration using default values."""
    for provider in self.options_providers:
        provider.load_defaults()

def generate_config(
    self, stream: TextIO | None = None, skipsections: tuple[str, ...] = ()
) -> None:
    """Write a configuration file according to the current configuration
    into the given stream or stdout.
    """
    options_by_section: dict[str, list[tuple[str, OptionDict, Any]]] = {}
    sections = []
    for provider in self.options_providers:
        for section, options in provider.options_by_section():
            if section is None:
                section = provider.name
            if section in skipsections:
                continue
            options = [
                (n, d, v)
                for (n, d, v) in options
                if d.get("type") is not None and not d.get("deprecated")
            ]
            if not options:
                continue
            if section not in sections:
                sections.append(section)
            all_options = options_by_section.setdefault(section, [])
            all_options += options
    stream = stream or sys.stdout
    printed = False
    for section in sections:
        if printed:
            print("\n", file=stream)
        utils.format_section(
            stream, section.upper(), sorted(options_by_section[section])
        )
        printed = True

def read_config_file(
    self, config_file: Path | None = None, verbose: bool = False
) -> None:
    """Read the configuration file but do not load it (i.e. dispatching
    values to each option's provider).
    """
    if config_file:
        config_file = Path(os.path.expandvars(config_file)).expanduser()
        if not config_file.exists():
            raise OSError(f"The config file {str(config_file)} doesn't exist!")

        parser = self.cfgfile_parser
        if config_file.suffix == ".toml":
            try:
                self._parse_toml(config_file, parser)
            except tomllib.TOMLDecodeError:
                pass
        else:
            # Use this encoding in order to strip the BOM marker, if any.
            with open(config_file, encoding="utf_8_sig") as fp:
                parser.read_file(fp)
            # normalize each section's title
            for sect, values in list(parser._sections.items()):
                if sect.startswith("pylint."):
                    sect = sect[len("pylint.") :]
                if not sect.isupper() and values:
                    parser._sections[sect.upper()] = values

    if not verbose:
        return
    if config_file and config_file.exists():
        msg = f"Using config file '{config_file}'"
    else:
        msg = "No config file found, using default configuration"
    print(msg, file=sys.stderr)

def load_configuration_from_config(self, config):
    for opt, opt_value in config.items():
        opt = opt.replace("_", "-")
        provider = self._all_options[opt]
        provider.set_option(opt, opt_value)

def to_xml(self):
    testcase = Junit.testcase(time="%.3f" % self.duration, **self.attrs)
    testcase.append(self.make_properties_node())
    for node in self.nodes:
        testcase.append(node)
    return testcase

def _get_global_properties_node(self):
    """Return a Junit node containing custom properties, if any.
    """
    if self.global_properties:
        return Junit.properties(
            [
                Junit.property(name=name, value=value)
                for name, value in self.global_properties
            ]
        )
    return ""

def _collect_probas(self, X):
    """Collect results from clf.predict calls. """
    return np.asarray([clf.predict_proba(X) for clf in self.estimators_])

def _replace_estimator(self, attr, name, new_val):
    # assumes `name` is a valid estimator name
    new_estimators = list(getattr(self, attr))
    for i, (estimator_name, _) in enumerate(new_estimators):
        if estimator_name == name:
            new_estimators[i] = (name, new_val)
            break
    setattr(self, attr, new_estimators)

def get_module_members(self) -> Dict[str, ObjectMember]:
    """Get members of target module."""
    if self.analyzer:
        attr_docs = self.analyzer.attr_docs
    else:
        attr_docs = {}

    members = {}  # type: Dict[str, ObjectMember]
    for name in dir(self.object):
        try:
            value = safe_getattr(self.object, name, None)
            docstring = attr_docs.get(('', name), [])
            members[name] = ObjectMember(name, value, docstring="\n".join(docstring))
        except AttributeError:
            continue

    # annotation only member (ex. attr: int)
    try:
        for name in inspect.getannotations(self.object):
            if name not in members:
                docstring = attr_docs.get(('', name), [])
                members[name] = ObjectMember(name, INSTANCEATTR,
                                             docstring="\n".join(docstring))
    except AttributeError:
        pass

    return members

def get_object_members(self, want_all: bool) -> Tuple[bool, ObjectMembers]:
    members = self.get_module_members()
    if want_all:
        if not self.__all__:
            # for implicit module members, check __module__ to avoid
            # documenting imported objects
            return True, list(members.values())
        else:
            for member in members.values():
                if member.__name__ not in self.__all__:
                    member.skipped = True

            return False, list(members.values())
    else:
        memberlist = self.options.members or []
        ret = []
        for name in memberlist:
            if name in members:
                ret.append(members[name])
            else:
                logger.warning(__('missing attribute mentioned in :members: option: '
                                  'module %s, attribute %s') %
                               (safe_getattr(self.object, '__name__', '???'), name),
                               type='autodoc')
        return False, ret

def resolve_name(self, modname: str, parents: Any, path: str, base: Any
                 ) -> Tuple[str, List[str]]:
    if modname is not None:
        logger.warning(__('"::" in automodule name doesn\'t make sense'),
                       type='autodoc')
    return (path or '') + base, []

def _eval_is_integer(self):
    from sympy.core.logic import fuzzy_and, fuzzy_not
    p, q = self.args
    if fuzzy_and([p.is_integer, q.is_integer, fuzzy_not(q.is_zero)]):
        return True

