def doit(p, q):
    """Try to return p % q if both are numbers or +/-p is known
    to be less than or equal q.
    """

    if p.is_infinite or q.is_infinite or p is nan or q is nan:
        return nan
    if (p == q or p == -q or
            p.is_Pow and p.exp.is_Integer and p.base == q or
            p.is_integer and q == 1):
        return S.Zero

    if q.is_Number:
        if p.is_Number:
            return (p % q)
        if q == 2:
            if p.is_even:
                return S.Zero
            elif p.is_odd:
                return S.One

    # by ratio
    r = p/q
    try:
        d = int(r)
    except TypeError:
        pass
    else:
        if type(d) is int:
            rv = p - d*q
            if (rv*q < 0) == True:
                rv += q
            return rv

    # by difference
    d = p - q
    if d.is_negative:
        if q.is_negative:
            return d
        elif q.is_positive:
            return p

def __init__(self, expr, base_exc=None):
    self.expr = expr
    self.base_exc = base_exc

def _print_MatAdd(self, expr):
    s = None
    for item in expr.args:
        pform = self._print(item)
        if s is None:
            s = pform     # First element
        else:
            if S(item.args[0]).is_negative:
                s = prettyForm(*stringPict.next(s, ' '))
                pform = self._print(item)
            else:
                s = prettyForm(*stringPict.next(s, ' + '))
            s = prettyForm(*stringPict.next(s, pform))

    return s

def __new__(cls, *args, **kwargs):
    evaluate = kwargs.get('evaluate', global_evaluate[0])
    on_morph = kwargs.get('on_morph', 'ignore')

    # unpack into coords
    coords = args[0] if len(args) == 1 else args

    # check args and handle quickly handle Point instances
    if isinstance(coords, Point):
        # even if we're mutating the dimension of a point, we
        # don't reevaluate its coordinates
        evaluate = False
        if len(coords) == kwargs.get('dim', len(coords)):
            return coords

    if not is_sequence(coords):
        raise TypeError(filldedent('''
            Expecting sequence of coordinates, not `{}`'''
                                   .format(func_name(coords))))
    # A point where only `dim` is specified is initialized
    # to zeros.
    if len(coords) == 0 and kwargs.get('dim', None):
        coords = (S.Zero,)*kwargs.get('dim')

    coords = Tuple(*coords)
    dim = kwargs.get('dim', len(coords))

    if len(coords) < 2:
        raise ValueError(filldedent('''
            Point requires 2 or more coordinates or
            keyword `dim` > 1.'''))
    if len(coords) != dim:
        message = ("Dimension of {} needs to be changed "
                   "from {} to {}.").format(coords, len(coords), dim)
        if on_morph == 'ignore':
            pass
        elif on_morph == "error":
            raise ValueError(message)
        elif on_morph == 'warn':
            warnings.warn(message)
        else:
            raise ValueError(filldedent('''
                    on_morph value should be 'error',
                    'warn' or 'ignore'.'''))
    if any(coords[dim:]):
        raise ValueError('Nonzero coordinates cannot be removed.')
    if any(a.is_number and im(a) for a in coords):
        raise ValueError('Imaginary coordinates are not permitted.')
    if not all(isinstance(a, Expr) for a in coords):
        raise TypeError('Coordinates must be valid SymPy expressions.')

    # pad with zeros appropriately
    coords = coords[:dim] + (S.Zero,)*(dim - len(coords))

    # Turn any Floats into rationals and simplify
    # any expressions before we instantiate
    if evaluate:
        coords = coords.xreplace(dict(
            [(f, simplify(nsimplify(f, rational=True)))
             for f in coords.atoms(Float)]))

    # return 2D or 3D instances
    if len(coords) == 2:
        kwargs['_nocheck'] = True
        return Point2D(*coords, **kwargs)
    elif len(coords) == 3:
        kwargs['_nocheck'] = True
        return Point3D(*coords, **kwargs)

    # the general Point
    return GeometryEntity.__new__(cls, *coords)

def __div__(self, divisor):
    """Divide point's coordinates by a factor."""
    divisor = sympify(divisor)
    coords = [simplify(x/divisor) for x in self.args]
    return Point(coords, evaluate=False)

def ambient_dimension(self):
    """Number of components this point has."""
    return getattr(self, '_ambient_dimension', len(self))

def _eval_power(self, expt):
    if expt.is_positive:
        return self
    if expt.is_negative:
        return S.ComplexInfinity
    if expt.is_extended_real is False:
        return S.NaN
    # infinities are already handled with pos and neg
    # tests above; now throw away leading numbers on Mul
    # exponent
    coeff, terms = expt.as_coeff_Mul()
    if coeff.is_negative:
        return S.ComplexInfinity**terms
    if coeff is not S.One:  # there is a Number to discard
        return self**terms

def _eval_power(self, expt):
    """
    ``expt`` is symbolic object but not equal to 0 or 1.

    ================ ======= ==============================
    Expression       Result  Notes
    ================ ======= ==============================
    ``oo ** nan``    ``nan``
    ``oo ** -p``     ``0``   ``p`` is number, ``oo``
    ================ ======= ==============================

    See Also
    ========
    Pow
    NaN
    NegativeInfinity

    """
    from sympy.functions import re

    if expt.is_extended_positive:
        return S.Infinity
    if expt.is_extended_negative:
        return S.Zero
    if expt is S.NaN:
        return S.NaN
    if expt is S.ComplexInfinity:
        return S.NaN
    if expt.is_extended_real is False and expt.is_number:
        expt_real = re(expt)
        if expt_real.is_positive:
            return S.ComplexInfinity
        if expt_real.is_negative:
            return S.Zero
        if expt_real.is_zero:
            return S.NaN

        return self**expt.evalf()

def _eval_power(self, expt):
    if expt is S.ComplexInfinity:
        return S.NaN

    if isinstance(expt, Number):
        if expt.is_zero:
            return S.NaN
        else:
            if expt.is_positive:
                return S.ComplexInfinity
            else:
                return S.Zero

def _eval_power(self, other):
    from sympy import arg, exp, floor, im, log, re, sign
    b, e = self.as_base_exp()
    if b is S.NaN:
        return (b**e)**other  # let __new__ handle it

    s = None
    if other.is_integer:
        s = 1
    elif b.is_polar:  # e.g. exp_polar, besselj, var('p', polar=True)...
        s = 1
    elif e.is_extended_real is not None:
        # helper functions ===========================
        def _half(e):
            """Return True if the exponent has a literal 2 as the
            denominator, else None."""
            if getattr(e, 'q', None) == 2:
                return True
            n, d = e.as_numer_denom()
            if n.is_integer and d == 2:
                return True
        def _n2(e):
            """Return ``e`` evaluated to a Number with 2 significant
            digits, else None."""
            try:
                rv = e.evalf(2, strict=True)
                if rv.is_Number:
                    return rv
            except PrecisionExhausted:
                pass
        # ===================================================
        if e.is_extended_real:
            # we need _half(other) with constant floor or
            # floor(S.Half - e*arg(b)/2/pi) == 0

            # handle -1 as special case
            if e == -1:
                # floor arg. is 1/2 + arg(b)/2/pi
                if _half(other):
                    if b.is_negative is True:
                        return S.NegativeOne**other*Pow(-b, e*other)
                    elif b.is_negative is False:
                        return Pow(b, -other)
            elif e.is_even:
                if b.is_extended_real:
                    b = abs(b)
                if b.is_imaginary:
                    b = abs(im(b))*S.ImaginaryUnit

            if (abs(e) < 1) == True or e == 1:
                s = 1  # floor = 0
            elif b.is_extended_nonnegative:
                s = 1  # floor = 0
            elif re(b).is_extended_nonnegative and (abs(e) < 2) == True:
                s = 1  # floor = 0
            elif fuzzy_not(im(b).is_zero) and abs(e) == 2:
                s = 1  # floor = 0
            elif _half(other):
                s = exp(2*S.Pi*S.ImaginaryUnit*other*floor(
                    S.Half - e*arg(b)/(2*S.Pi)))
                if s.is_extended_real and _n2(sign(s) - s) == 0:
                    s = sign(s)
                else:
                    s = None
        else:
            # e.is_extended_real is False requires:
            #     _half(other) with constant floor or
            #     floor(S.Half - im(e*log(b))/2/pi) == 0
            try:
                s = exp(2*S.ImaginaryUnit*S.Pi*other*
                    floor(S.Half - im(e*log(b))/2/S.Pi))
                # be careful to test that s is -1 or 1 b/c sign(I) == I:
                # so check that s is real
                if s.is_extended_real and _n2(sign(s) - s) == 0:
                    s = sign(s)
                else:
                    s = None
            except PrecisionExhausted:
                s = None

    if s is not None:
        return s*Pow(b, e*other)

def _build(self, code, name):
    ns = {}
    exec(code, ns)
    return ns[name]

def __init__(self, monom, gens=None):
    if not iterable(monom):
        rep, gens = dict_from_expr(sympify(monom), gens=gens)
        if len(rep) == 1 and list(rep.values())[0] == 1:
            monom = list(rep.keys())[0]
        else:
            raise ValueError("Expected a monomial got {}".format(monom))

    self.exponents = tuple(map(int, monom))
    self.gens = gens

def monomial_key(order=None, gens=None):
    """
    Return a function defining admissible order on monomials.

    The result of a call to :func:`monomial_key` is a function which should
    be used as a key to :func:`sorted` built-in function, to provide order
    in a set of monomials of the same length.

    Currently supported monomial orderings are:

    1. lex       - lexicographic order (default)
    2. grlex     - graded lexicographic order
    3. grevlex   - reversed graded lexicographic order
    4. ilex, igrlex, igrevlex - the corresponding inverse orders

    If the ``order`` input argument is not a string but has ``__call__``
    attribute, then it will pass through with an assumption that the
    callable object defines an admissible order on monomials.

    If the ``gens`` input argument contains a list of generators, the
    resulting key function can be used to sort SymPy ``Expr`` objects.

    """
    if order is None:
        order = lex

    if isinstance(order, Symbol):
        order = str(order)

    if isinstance(order, str):
        try:
            order = _monomial_key[order]
        except KeyError:
            raise ValueError("supported monomial orderings are 'lex', 'grlex' and 'grevlex', got %r" % order)
    if hasattr(order, '__call__'):
        if gens is not None:
            def _order(expr):
                return order(expr.as_poly(*gens).degree_list())
            return _order
        return order
    else:
        raise ValueError("monomial ordering specification must be a string or a callable, got %s" % order)

def mul(self):
    name = "monomial_mul"
    template = dedent("""\
    def %(name)s(A, B):
        (%(A)s,) = A
        (%(B)s,) = B
        return (%(AB)s,)
    """)
    A = self._vars("a")
    B = self._vars("b")
    AB = [ "%s + %s" % (a, b) for a, b in zip(A, B) ]
    code = template % dict(name=name, A=", ".join(A), B=", ".join(B), AB=", ".join(AB))
    return self._build(code, name)

def pow(self):
    name = "monomial_pow"
    template = dedent("""\
    def %(name)s(A, k):
        (%(A)s,) = A
        return (%(Ak)s,)
    """)
    A = self._vars("a")
    Ak = [ "%s*k" % a for a in A ]
    code = template % dict(name=name, A=", ".join(A), Ak=", ".join(Ak))
    return self._build(code, name)

def ldiv(self):
    name = "monomial_ldiv"
    template = dedent("""\
    def %(name)s(A, B):
        (%(A)s,) = A
        (%(B)s,) = B
        return (%(AB)s,)
    """)
    A = self._vars("a")
    B = self._vars("b")
    AB = [ "%s - %s" % (a, b) for a, b in zip(A, B) ]
    code = template % dict(name=name, A=", ".join(A), B=", ".join(B), AB=", ".join(AB))
    return self._build(code, name)

def lcm(self):
    name = "monomial_lcm"
    template = dedent("""\
    def %(name)s(A, B):
        (%(A)s,) = A
        (%(B)s,) = B
        return (%(AB)s,)
    """)
    A = self._vars("a")
    B = self._vars("b")
    AB = [ "%s if %s >= %s else %s" % (a, a, b, b) for a, b in zip(A, B) ]
    code = template % dict(name=name, A=", ".join(A), B=", ".join(B), AB=", ".join(AB))
    return self._build(code, name)
